arguments.command:
cd /app && python3 -c "
seqs={}; name=None
for line in open('sequences.fasta'):
    line=line.strip()
    if line.startswith('>'): name=line[1:]; seqs[name]=''
    else: seqs[name]+=line
inp=seqs['input']
P=215
def rc(s):
    c={'a':'t','t':'a','g':'c','c':'g'}
    return ''.join(c[x] for x in reversed(s))
import subprocess
def tm(s):
    o=subprocess.run(['oligotm','-tp','1','-sc','1','-mv','50','-dv','2','-n','0.8','-d','500',s.upper()],capture_output=True,text=True)
    return float(o.stdout.strip())
print('FWD anneal (downstream inp[215:215+L]):')
for L in range(15,37):
    s=inp[P:P+L]
    print(L, round(tm(s),2), s)
print('REV anneal region top-strand inp[215-L:215], primer=revcomp:')
for L in range(15,37):
    s=inp[P-L:P]
    print(L, round(tm(rc(s)),2), rc(s))
"

